from dataclasses import dataclass

@dataclass
class ForecastAccuracyRecord:
    team:              str
    period_month:      str
    week2_forecast:    float   # EOM forecast made at end of week 2
    actual_close:      float
    error_pct:         float   # (actual - forecast) / actual

    @property
    def is_within_target(self) -> bool:
        return abs(self.error_pct) <= 0.15

def compute_accuracy_kpi(
    records: list[ForecastAccuracyRecord],
) -> dict:
    within_target = [r for r in records if r.is_within_target]
    return {
        "total_forecasts":   len(records),
        "within_target":     len(within_target),
        "accuracy_rate_pct": len(within_target) / len(records) * 100 if records else 0,
        "mean_error_pct":    sum(abs(r.error_pct) for r in records) / len(records) if records else 0,
        "worst_team":        max(records, key=lambda r: abs(r.error_pct)).team if records else None,
    }
